  if (!write_result) {
    // Handle table creation error
    return {};
  }

  // Create Enrollment table  
  write_result = sqlgen::write(conn, empty_enrollments);
  if (!write_result) {
    // Handle table creation error
    return {};
  }

  // 3. Build and execute the query
  auto query = sqlgen::select_from<Course, "c">("title"_t1)
    | sqlgen::left_join<Enrollment, "e">("course_id"_t1 == "course_id"_t2)
    | sqlgen::group_by("title"_t1)
    | sqlgen::select("title"_t1, sqlgen::count("enrollment_id"_t2).as("student_count"), 
                       sqlgen::avg("grade"_t2).as("avg_grade"))
    | sqlgen::to<std::vector<CourseStatsView>>;

  auto result = query(conn);
  if (!result) {
    // Handle query execution error
    return {};
  }

  // 4. Convert results to CourseStats
  auto stats = result.value();
  std::vector<CourseStats> final_result;
  final_result.reserve(stats.size());

  for (const auto& view : stats) {
    final_result.push_back(CourseStats{
      .title = view.title,
      .student_count = view.student_count,
      .avg_grade = view.avg_grade
    });
  }

  return final_result;
}

}  // namespace query_course_enrollment_stats
