std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = *conn_result;

    // Build the base query
    auto query = sqlgen::read<std::vector<Book>>;

    // Conditionally add WHERE clauses based on provided filters
    auto condition = sqlgen::Condition::make(true); // Start with true condition

    if (filters.title_keyword) {
        auto title_condition = "title"_c.like("%" + *filters.title_keyword + "%");
        condition = condition && title_condition;
    }

    if (filters.min_year) {
        auto year_condition = "year"_c >= *filters.min_year;
        condition = condition && year_condition;
    }

    if (filters.genre) {
        auto genre_condition = "genre"_c == *filters.genre;
        condition = condition && genre_condition;
    }

    if (filters.max_price) {
        auto price_condition = "price"_c <= *filters.max_price;
        condition = condition && price_condition;
    }

    // Apply the condition to the query
    if (condition) {
        query = query | sqlgen::where(*condition);
    }

    // Execute the query and return results
    auto result = query(conn);
    if (!result) {
        throw std::runtime_error("Query execution failed");
