#pragma once

#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace schema_manage_indexes {

  struct Product {
    sqlgen::PrimaryKey<int> product_id;
    std::string sku;
    std::string name;
    std::string category;
    double price;
  };

  bool manage_indexes() {
    // Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
      return false;
    }
    auto conn = *conn_result;

    // Create the Product table if it doesn't exist
    auto table_creation = sqlgen::create_table<Product> | sqlgen::if_not_exists;
    auto table_result = table_creation(conn);
    if (!table_result) {
      return false;
    }

    // Create indexes using sqlgen::create_index with appropriate parameters
    using namespace sqlgen::literals; // For the _c literal

    // 1. Create standard index on category with IF NOT EXISTS
    auto idx_category = sqlgen::create_index<"idx_product_category", Product>("category"_c) | sqlgen::if_not_exists;
    auto idx_category_result = idx_category(conn);
    if (!idx_category_result) {
      return false;
    }

    // 2. Create unique index on sku with IF NOT EXISTS
    auto idx_sku = sqlgen::create_index<"idx_product_sku", Product>("sku"_c) | sqlgen::if_not_exists;
    idx_sku.unique_ = true; // Set unique flag
    auto idx_sku_result = idx_sku(conn);
    if (!idx_sku_result) {
      return false;
    }

    // 3. Create composite index on (name, price) with IF NOT EXISTS
    auto idx_name_price = sqlgen::create_index<"idx_product_name_price", Product>("name"_c, "price"_c) | sqlgen::if_not_exists;
    auto idx_name_price_result = idx_name_price(conn);
    if (!idx_name_price_result) {
      return false;
    }

    return true;
  }

}  // namespace schema_manage_indexes
```

