```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // Begin transaction
  auto begin_result = sqlgen::begin_transaction(conn);
  if (!begin_result) {
    return false;
  }

  try {
    // Read from_account to check balance
    auto from_account_result = (sqlgen::read<Account> | where("account_id"_c == from_account_id))(conn);
    if (!from_account_result) {
      sqlgen::rollback(conn);
      return false;
    }

    auto from_account = from_account_result.value();
    if (from_account.balance < amount) {
      sqlgen::rollback(conn);
      return false;
    }

    // Update from_account: balance = balance - amount
    auto update_from_result = (sqlgen::update<Account>("balance"_c.set("balance"_c - amount)) 
                             | where("account_id"_c == from_account_id && "balance"_c >= amount))(conn);
    if (!update_from_result) {
      sqlgen::rollback(conn);
      return false;
    }

    // Update to_account: balance = balance + amount
    auto update_to_result = (sqlgen::update<Account>("balance"_c.set("balance"_c + amount)) 
                           | where("account_id"_c == to_account_id))(conn);
    if (!update_to_result) {
      sqlgen::rollback(conn);
      return false;
    }

    // Commit transaction
    auto commit_result = sqlgen::commit(conn);
    if (!commit_result) {
      sqlgen::rollback(conn);
      return false;
    }

    return true;

  } catch (...) {
    // Rollback on any exception
    sqlgen::rollback(conn);
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Transaction Management**: 
   - Begins transaction with `sqlgen::begin_transaction(conn)`
   - Commits with `sqlgen::commit(conn)` on success
   - Rolls back with `sqlgen::rollback(conn)` on failure
3. **Balance Verification**: Reads from_account using `sqlgen::read<Account>` with where condition to check sufficient funds
4. **Update Operations**: Uses `sqlgen::update<Account>` with set operations:
   - `"balance"_c.set("balance"_c - amount)` for deduction
   - `"balance"_c.set("balance"_c + amount)` for addition
5. **Condition Checks**: Uses where conditions to ensure updates only affect the correct accounts
6. **Error Handling**: Comprehensive error checking at each step with proper rollback

The implementation follows the exact SQL logic specified while leveraging sqlgen's fluent API for type-safe database operations.

