  int stock;
};

struct Sale {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct SalesSummary {
  static constexpr bool is_view = true;
  std::string product_name;
  int total_quantity;
  double total_revenue;
};

/**
 * Function: Create a view SalesSummary that aggregates sales by product.
 * 
 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  using namespace sqlgen::literals;

  // 1. Construct the SELECT query using sqlgen::select_from with table aliases
  auto query = sqlgen::select_from<Sale, "s">(
      "name"_p | sqlgen::as<"product_name">,
      sqlgen::sum("quantity"_s) | sqlgen::as<"total_quantity">,
      sqlgen::sum("amount"_s) | sqlgen::as<"total_revenue">
  )
  // 2. Add INNER JOIN between Sale and Product tables
  | sqlgen::inner_join<Product, "p">("product_id"_s == "product_id"_p)
  // 3. Apply GROUP BY on product name column
  | sqlgen::group_by("name"_p);

  // 4. Create the view using sqlgen::create_as<SalesSummary>
  auto create_stmt = sqlgen::create_as<SalesSummary>(query) | sqlgen::if_not_exists;

  // 5. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // 6. Execute the CREATE VIEW statement
  auto result = create_stmt(conn);

  // 7. Handle error checking
  if (!result) {
    return false;
  }

  return true;
}
}  // namespace schema_create_view_sales_summary
