 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) return {};
  auto conn = conn_res.value();

  create_table<Department>(conn);
  create_table<Project>(conn);

  const auto query =
      select_from<Project, "p">(col<"name", "d"> | as<"department_name">,
                                col<"name", "p"> | as<"project_name">) |
      left_join<Department, "d">(col<"department_id", "p"> == col<"department_id", "d">) |
      to<std::vector<DepProj>>;
  return query(conn).value();
