 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");

  if (!conn_result) {
    return false; // Connection failed
  }

  // Perform upsert operation with write API
  auto write_result = sqlgen::write(conn_result.value(), items, true);

  if (!write_result) {
    return false; // Upsert operation failed
  }

  // Read back the items to verify upsert behavior
  auto read_result = sqlgen::read<std::vector<Inventory>>(write_result.value());

  if (!read_result) {
    return false; // Read operation failed
  }

  // Verify that the upserted items match the original items
  const auto& read_items = read_result.value();
  if (items.size() != read_items.size()) {
    return false; // Size mismatch
  }

  for (size_t i = 0; i < items.size(); ++i) {
    if (items[i].item_id != read_items[i].item_id ||
        items[i].name != read_items[i].name ||
        items[i].quantity != read_items[i].quantity) {
      return false; // Data mismatch found
    }
  }

  return true; // All operations completed successfully
}

}  // namespace upsert_inventory_items

