#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace analyze_social_network {

struct User {
    sqlgen::PrimaryKey<int> user_id;
    std::string username;
    std::string email;
    sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
    std::optional<std::string> city;
};

struct Friendship {
    int user_id1;
    int user_id2;
    sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> friendship_date;
};

struct FriendConnection {
    std::string user1_name;
    std::string user2_name;
};

struct MutualFriend {
    std::string user1;
    std::string user2;
    int mutual_count;
};

struct FriendStats {
    int user_id;
    std::string username;
    int friend_count;
};

struct FriendOfFriend {
    std::string user1;
    std::string user2;
};

struct Recommendation {
    std::string user1;
    std::string user2;
    std::string city;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    using namespace sqlgen::literals;

    // Connect to in-memory SQLite database
    auto conn = sqlgen::sqlite::connect();

    // Create tables using sqlgen's type system
    auto create_user_table = sqlgen::create_table<User>;
    auto create_friendship_table = sqlgen::create_table<Friendship>;

    // Insert data into tables
    auto insert_users = sqlgen::insert(users);
    auto insert_friendships = sqlgen::insert(friendships);

    // Query 1: Find mutual friends using SELF-JOIN
    auto mutual_friends_query = sqlgen::read<std::vector<MutualFriend>>
        | sqlgen::select_from<User, "u1">("username"_t1.as<"user1">, "username"_t2.as<"user2">)
        | sqlgen::inner_join<Friendship, "f1">("user_id1"_t1 == "user_id"_t1 && "user_id2"_t1 == "user_id"_t2)
        | sqlgen::inner_join<User, "u2">("user_id2"_t1 == "user_id"_t2)
        | sqlgen::where("u1"_t1 < "u2"_t1)
        | sqlgen::group_by("u1"_t1, "u2"_t1)
        | sqlgen::having(sqlgen::count() > 0);

    // Query 2: Find users with more than average friends using nested query
    auto avg_subquery = sqlgen::select_from<Friendship>("user_id1"_t1)
        | sqlgen::group_by("user_id1"_t1)
        | sqlgen::select(sqlgen::count().as<"friend_count">);

    auto above_avg_query = sqlgen::read<std::vector<FriendStats>>
        | sqlgen::select_from<User>("user_id"_t1, "username"_t1)
        | sqlgen::left_join<Friendship, "f">("user_id1"_t1 == "user_id"_t1)
        | sqlgen::group_by("user_id"_t1)
        | sqlgen::having(sqlgen::count() > 
            sqlgen::select_from<decltype(avg_subquery)>("friend_count"_t1)
            | sqlgen::select(sqlgen::avg("friend_count"_t1))
        );

    // Query 3: Find friend-of-friend relationships
    auto friend_of_friend_query = sqlgen::read<std::vector<FriendOfFriend>>
        | sqlgen::select_from<Friendship, "f1">("user_id1"_t1, "user_id2"_t1)
        | sqlgen::inner_join<Friendship, "f2">("user_id2"_t1 == "user_id1"_t2)
        | sqlgen::inner_join<Friendship, "f3">("user_id2"_t2 == "user_id1"_t3)
        | sqlgen::where("user_id1"_t1 != "user_id2"_t3);

    // Query 4: Count friends per user and find most connected users
    auto friend_count_query = sqlgen::read<std::vector<FriendStats>>
        | sqlgen::select_from<User>("user_id"_t1, "username"_t1)
        | sqlgen::left_join<Friendship, "f">("user_id1"_t1 == "user_id"_t1)
        | sqlgen::group_by("user_id"_t1)
        | sqlgen::select(sqlgen::count().as<"friend_count">);

    // Query 5: Recommend users in same city not yet friends
    auto recommendation_query = sqlgen::read<std::vector<Recommendation>>
        | sqlgen::select_from<User, "u1">("username"_t1.as<"user1">, "city"_t1)
        | sqlgen::inner_join<User, "u2">("city"_t1 == "city"_t2 && "user_id"_t1 < "user_id"_t2)
        | sqlgen::where(!sqlgen::exists(
            sqlgen::select_from<Friendship>("user_id1"_t1, "user_id2"_t1)
            | sqlgen::where(("user_id1"_t1 == "user_id"_t1 && "user_id2"_t1 == "user_id"_t2) || 
                         ("user_id1"_t1 == "user_id"_t2 && "user_id2"_t1 == "user_id"_t1))
        ));

    // Execute all queries against the database connection
    auto mutual_results = mutual_friends_query(conn);
    auto avg_results = above_avg_query(conn);
    auto foaf_results = friend_of_friend_query(conn);
    auto count_results = friend_count_query(conn);
    auto rec_results = recommendation_query(conn);

    // Convert results to FriendConnection format (mutual friends as example)
    std::vector<FriendConnection> results;
    for (const auto& result : mutual_results.value()) {
        results.push_back(FriendConnection{
            .user1_name = result.user1,
            .user2_name = result.user2
        });
    }

    return results;
}

}  // namespace analyze_social_network

