  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }
  auto conn = *conn_result;

  // Create tables
  auto create_parent_result = sqlgen::create_table<Parent>(conn);
  if (!create_parent_result) {
    return false; // Failed to create parent table
  }

  auto create_child_result = sqlgen::create_table<Child>(conn);
  if (!create_child_result) {
    return false; // Failed to create child table
  }

  // Insert parent and child records
  Parent parent{1, "Test Parent"};
  Child child{1, 1, "Test Child Note"};

  auto insert_parent_result = sqlgen::insert(parent)(conn);
  if (!insert_parent_result) {
    return false; // Failed to insert parent
  }

  auto insert_child_result = sqlgen::insert(child)(conn);
  if (!insert_child_result) {
    return false; // Failed to insert child
  }

  // Verify child exists before deletion
  auto read_child_before = sqlgen::read<std::vector<Child>> | sqlgen::where("parent_id"_c == 1);
  auto child_before_result = read_child_before(conn);
  if (!child_before_result || child_before_result->empty()) {
    return false; // Child didn't exist before deletion
  }

  // Delete parent and check if child is deleted
  auto delete_result = sqlgen::delete_from<Parent> | sqlgen::where("parent_id"_c == 1);
  auto delete_exec_result = delete_result(conn);
  if (!delete_exec_result) {
    return false; // Delete operation failed
