  // Verify child was deleted
  auto read_child_after = sqlgen::read<std::vector<Child>> | sqlgen::where("parent_id"_c == 1);
  auto child_after_result = read_child_after(conn);

  // If child still exists, return false (cascade failed)
  // If child doesn't exist, return true (cascade worked)
  return child_after_result && child_after_result->empty();
}

