};

/**
 * description: select_from_read_to_vector.
 * This function demonstrates how to read data from a table using sqlgen read API and store it in a vector.
 * It returns a vector of Book structs, where each struct contains the book_id, title, and pages.
 * Returns: std::vector<Book>, ordered by pages in descending order.
 */
std::vector<Book> select_from_read_to_vector() {
  using namespace sqlgen::literals;

  // 1. Create an in-memory database connection
  auto conn_result = sqlgen::sqlite::connect();

  // 2. Create a read operation for std::vector<Book>
  auto read_op = sqlgen::read<std::vector<Book>>;

  // 3. Apply order_by with pages column in descending order
  auto ordered_read = read_op | sqlgen::order_by("pages"_c.desc());

  // 4. Execute the query by calling the read operation with the connection
  auto result = ordered_read(conn_result.value());

  // 5. Handle the Result object to extract the vector
  return result.value();
}

}  // namespace select_from_read_to_vector
```

