Based on the reference materials and detailed specifications, here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    using namespace sqlgen::literals;

    // Create SELECT query from Source table
    auto select_query = sqlgen::select_from<Source>("value"_c);

    // Apply WHERE condition (value > 100)
    auto filtered_query = select_query | sqlgen::where("value"_c > 100);

    // Create CREATE TABLE AS statement for Target table
    return sqlgen::create_as<Target>(filtered_query);
}

}  // namespace create_table_as_select
```

**Explanation:**

1. **`sqlgen::select_from<Source>("value"_c)`**: Creates a SELECT query from the `Source` table, selecting the `value` column using the column literal `"value"_c`.

2. **`select_query | sqlgen::where("value"_c > 100)`**: Applies the WHERE condition using the pipe operator `|` to chain the `where` clause. The condition `"value"_c > 100` uses the column literal and comparison operator.

3. **`sqlgen::create_as<Target>(filtered_query)`**: Creates a CREATE TABLE AS statement for the `Target` table using the filtered SELECT query.

4. **Return value**: The function returns the query object as specified in the requirements.

